\section*{Solução Técnica}
\textbf{Resposta final:} $1,9 \times 10^{6}$ toneladas (Alternativa D)\\

\textbf{Justificativa:} A questão solicita o cálculo da massa de bauxita que deixou de ser extraída da natureza devido à reciclagem das latas de alumínio em 2020 no Brasil.

\textbf{Estratégia:}
\begin{itemize}
  \item Calcular a massa de alumínio reciclada considerando o total de latas vendidas e o índice de reciclagem.
  \item Utilizar a relação entre bauxita e alumínio para determinar a massa de bauxita que teria sido necessária para produzir o alumínio reciclado.
\end{itemize}

\textbf{Passos para solução:}
\begin{enumerate}
  \item Massa total de latas vendidas: $4,0 \times 10^{5}$ toneladas.
  \item Massa de alumínio reciclado: 
  \[
    3,896 \times 10^{5} = 0{,}974 \times 4{,}0 \times 10^{5} \, \text{toneladas}
  \]
  \item Relação entre bauxita e alumínio: para cada 10 kg de alumínio, são usados 50 kg de bauxita.
  \item Massa de bauxita economizada:
  \[
    5 \times 3,896 \times 10^{5} = 1,948 \times 10^{6} \, \text{toneladas}
  \]
  \item Arredondando, obtém-se $1,9 \times 10^{6}$ toneladas.
\end{enumerate}

\textbf{Fórmulas utilizadas:}
\begin{equation*}
massa\_bauxita = 5 \times massa\_alumínio
\end{equation*}
\begin{equation*}
massa\_alumínio\_reciclado = percentual\_reciclagem \times massa\_total\_latas
\end{equation*}

payload.didacticExplanation:
\section*{Explicação Didática}

\textbf{Explicação sucinta:} Para descobrir quanto de bauxita foi poupado pela reciclagem, multiplicamos a massa de alumínio reciclado (calculada com base na porcentagem de reciclagem do total das latas vendidas) por 5, pois a produção de alumínio exige cinco vezes mais massa de bauxita.

\textbf{Passo a passo:}
\begin{enumerate}
  \item Identificar a massa total das latas vendidas: $4,0 \times 10^{5}$ toneladas.
  \item Calcular a massa reciclada: $0{,}974 \times 4,0 \times 10^{5} = 3,896 \times 10^{5}$ toneladas.
  \item Aplicar a proporção entre bauxita e alumínio: multiplicar a massa reciclada por 5.
  \item Resultado: $3,896 \times 10^{5} \times 5 = 1,948 \times 10^{6}$ toneladas de bauxita salvas.
  \item Arredondar para $1,9 \times 10^{6}$ toneladas, que corresponde à alternativa correta.
\end{enumerate}

\textbf{Erros comuns:}
\begin{itemize}
  \item Não aplicar o percentual de reciclagem.
  \item Esquecer de multiplicar por 5 para obter a massa de bauxita.
  \item Confundir unidades (kg e toneladas).
  \item Arredondar prematuramente ou de forma incorreta, perdendo a ordem de grandeza.
\end{itemize}

\textbf{Dicas para ensino:}
\begin{itemize}
  \item Enfatizar a leitura cuidadosa dos dados e interpretação dos percentuais.
  \item Explicar bem a relação química entre bauxita e alumínio, reforçando por que os cálculos usam a proporção.
  \item Mostrar a importância da notação científica para operações com grandes valores.
  \item Fomentar a verificação lógica dos resultados para evitar erros graves de escala.
\end{itemize}

